//! Loading the reviewer registry from disk.
//!
//! Reviewers are declarative and static, defined in a YAML file under the repo's
//! `bastion/` directory. Keeping them on disk (not generated by code) is what
//! makes them reviewable and gives a stable trigger set.

use std::path::{Path, PathBuf};

use color_eyre::eyre::{Context, Result, bail, eyre};
use serde::{Deserialize, Serialize};

use crate::reviewer::{Backend, Effort, ModelId, Reviewer};

/// The registry file name searched for within the `bastion/` config directory.
pub const REGISTRY_FILE: &str = "reviewers.yaml";

/// The config directory name, relative to the repository root.
pub const CONFIG_DIR: &str = "bastion";

/// The parsed reviewer registry.
#[derive(Debug, Clone, Default, PartialEq, Eq, Serialize, Deserialize)]
pub struct Config {
    /// Registry-wide defaults inherited by every reviewer that does not set the
    /// field itself.
    #[serde(default, skip_serializing_if = "Defaults::is_empty")]
    pub defaults: Defaults,
    /// The reviewers defined for this repository.
    #[serde(default)]
    pub reviewers: Vec<Reviewer>,
}

/// Registry-wide defaults applied to every reviewer at load time.
///
/// A reviewer's own field always wins; these fill the gaps. They sit *above* each
/// backend's built-in default (Opus 4.8 at high effort for Claude Code), so a repo
/// can set a house model and effort in one place without repeating them on every
/// reviewer.
#[derive(Debug, Clone, Default, PartialEq, Eq, Serialize, Deserialize)]
#[non_exhaustive]
pub struct Defaults {
    /// Default model for reviewers that do not pin one. Like a reviewer's own
    /// `model`, this is backend-specific: a reviewer that inherits it must pin a
    /// backend (the registry rejects an inherited model under `backend: any`).
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub model: Option<ModelId>,
    /// Default reasoning effort for reviewers that do not set one.
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub effort: Option<Effort>,
}

impl Defaults {
    /// Whether no registry-wide default is set (the serialized-form skip guard).
    #[must_use]
    pub fn is_empty(&self) -> bool {
        self.model.is_none() && self.effort.is_none()
    }
}

impl Config {
    /// Parse a registry from YAML text, validating reviewer-name uniqueness.
    ///
    /// # Errors
    ///
    /// Returns an error if the YAML is malformed or two reviewers share a name.
    pub fn from_yaml(yaml: &str) -> Result<Self> {
        let mut config: Config =
            serde_yaml_ng::from_str(yaml).wrap_err("reviewer registry is not valid YAML")?;
        config.apply_defaults();
        config.validate()?;
        Ok(config)
    }

    /// Load and parse the registry at `path`.
    ///
    /// # Errors
    ///
    /// Returns an error if the file cannot be read or fails [`Config::from_yaml`].
    pub fn load(path: &Path) -> Result<Self> {
        let yaml = std::fs::read_to_string(path)
            .wrap_err_with(|| format!("reading reviewer registry at {}", path.display()))?;
        Self::from_yaml(&yaml)
            .wrap_err_with(|| format!("parsing reviewer registry at {}", path.display()))
    }

    /// Discover and load the registry by walking up from `start` looking for
    /// `<dir>/bastion/reviewers.yaml`.
    ///
    /// # Errors
    ///
    /// Returns an error if no registry is found in any ancestor directory, or if
    /// the discovered file fails to load.
    pub fn discover(start: &Path) -> Result<Self> {
        let path = locate(start)
            .ok_or_else(|| eyre!("no reviewer registry found; expected {CONFIG_DIR}/{REGISTRY_FILE} in this repo or an ancestor"))?;
        Self::load(&path)
    }

    /// Fold the registry-wide [`Defaults`] into each reviewer: a reviewer's own
    /// `model`/`effort` wins, and the default fills the gap. Resolving here, once,
    /// means every downstream consumer (and the persisted run record) sees the
    /// effective values rather than re-deriving them, and the `model`-under-`any`
    /// guard in [`Config::validate`] catches an inherited model too.
    fn apply_defaults(&mut self) {
        let Defaults { model, effort } = &self.defaults;
        for reviewer in &mut self.reviewers {
            if reviewer.model.is_none() {
                reviewer.model = model.clone();
            }
            if reviewer.effort.is_none() {
                reviewer.effort = effort.clone();
            }
        }
    }

    fn validate(&self) -> Result<()> {
        let mut seen = std::collections::BTreeSet::new();
        for reviewer in &self.reviewers {
            if !seen.insert(reviewer.name.as_str()) {
                bail!("duplicate reviewer name: {}", reviewer.name);
            }
            // A model id means something only to the backend it names, so it only
            // makes sense once the backend is pinned. Reject a model under
            // `backend: any` (fail closed at the boundary) rather than letting, say,
            // a Codex id reach Claude Code once `any` resolves. This fires for an
            // inherited default model too, since `apply_defaults` ran first.
            if reviewer.model.is_some() && reviewer.backend == Backend::Any {
                bail!(
                    "reviewer '{}' sets a model but leaves backend: any; a model id is \
                     backend-specific, so pin a backend (claude-code or codex)",
                    reviewer.name
                );
            }
        }
        Ok(())
    }
}

/// Locate the registry file by walking up from `start`.
///
/// Returns the path to the first `<ancestor>/bastion/reviewers.yaml` found, or
/// `None` if none exists up to the filesystem root.
#[must_use]
pub fn locate(start: &Path) -> Option<PathBuf> {
    for dir in start.ancestors() {
        let candidate = dir.join(CONFIG_DIR).join(REGISTRY_FILE);
        if candidate.is_file() {
            return Some(candidate);
        }
    }
    None
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn loads_a_two_reviewer_registry() {
        let yaml = r"
reviewers:
  - name: file-responsibility
    trigger: [src/**/*.ts]
    mode: gate
    prompt: Check single responsibility.
  - name: api-compatibility
    trigger: [src/server/**, src/client/**]
    mode: gate
    prompt: Check API compatibility.
";
        let config = Config::from_yaml(yaml).expect("valid registry");
        assert_eq!(config.reviewers.len(), 2);
        assert_eq!(config.reviewers[0].name, "file-responsibility");
    }

    #[test]
    fn rejects_duplicate_reviewer_names() {
        let yaml = r"
reviewers:
  - name: dup
    trigger: [a]
    mode: gate
    prompt: one
  - name: dup
    trigger: [b]
    mode: advisor
    prompt: two
";
        let err = Config::from_yaml(yaml).unwrap_err();
        assert!(err.to_string().contains("duplicate reviewer name"));
    }

    #[test]
    fn registry_defaults_fill_unset_reviewer_fields_and_explicit_values_win() {
        let yaml = r"
defaults:
  model: gpt-5
  effort: high
reviewers:
  - name: inherits
    trigger: [src/**]
    mode: gate
    backend: codex
    prompt: p
  - name: overrides
    trigger: [src/**]
    mode: gate
    backend: codex
    model: gpt-5-codex
    effort: low
    prompt: p
";
        let config = Config::from_yaml(yaml).expect("valid registry");
        let inherits = &config.reviewers[0];
        assert_eq!(inherits.model.as_ref().map(ModelId::as_str), Some("gpt-5"));
        assert_eq!(inherits.effort.as_ref().map(Effort::as_str), Some("high"));
        let overrides = &config.reviewers[1];
        assert_eq!(
            overrides.model.as_ref().map(ModelId::as_str),
            Some("gpt-5-codex")
        );
        assert_eq!(overrides.effort.as_ref().map(Effort::as_str), Some("low"));
    }

    #[test]
    fn a_model_under_backend_any_is_rejected() {
        let yaml = r"
reviewers:
  - name: stray
    trigger: [src/**]
    mode: gate
    model: gpt-5
    prompt: p
";
        let err = Config::from_yaml(yaml).unwrap_err();
        assert!(
            err.to_string().contains("backend: any"),
            "error should explain the model needs a pinned backend, got: {err}"
        );
    }

    #[test]
    fn an_inherited_default_model_under_backend_any_is_also_rejected() {
        // The guard fires after defaults resolve, so a default model folded into a
        // `backend: any` reviewer is caught too.
        let yaml = r"
defaults:
  model: gpt-5
reviewers:
  - name: stray
    trigger: [src/**]
    mode: gate
    prompt: p
";
        let err = Config::from_yaml(yaml).unwrap_err();
        assert!(err.to_string().contains("backend: any"));
    }

    #[test]
    fn discovers_registry_in_an_ancestor_directory() {
        let tmp = tempfile::tempdir().unwrap();
        let config_dir = tmp.path().join(CONFIG_DIR);
        std::fs::create_dir_all(&config_dir).unwrap();
        std::fs::write(
            config_dir.join(REGISTRY_FILE),
            "reviewers:\n  - name: r\n    trigger: [x]\n    mode: gate\n    prompt: p\n",
        )
        .unwrap();

        let nested = tmp.path().join("src").join("deep");
        std::fs::create_dir_all(&nested).unwrap();

        let config = Config::discover(&nested).expect("found via ancestor walk");
        assert_eq!(config.reviewers.len(), 1);
    }

    #[test]
    fn discovery_fails_clearly_when_absent() {
        let tmp = tempfile::tempdir().unwrap();
        let err = Config::discover(tmp.path()).unwrap_err();
        assert!(err.to_string().contains("no reviewer registry found"));
    }

    #[test]
    fn the_shipped_registry_loads_and_is_well_formed() {
        // The registry under bastion/ is load-bearing: it is what Bastion uses to
        // review its own changes locally and in CI. Guard it so an edit that makes
        // it unparseable, duplicates a name, or leaves a reviewer empty fails here
        // rather than at review time.
        let path = Path::new(env!("CARGO_MANIFEST_DIR"))
            .join(CONFIG_DIR)
            .join(REGISTRY_FILE);
        let config = Config::load(&path).expect("shipped reviewers.yaml loads");

        assert!(
            !config.reviewers.is_empty(),
            "the shipped registry should define reviewers"
        );
        for reviewer in &config.reviewers {
            assert!(!reviewer.name.is_empty(), "reviewer name must be non-empty");
            assert!(
                !reviewer.trigger.is_empty(),
                "reviewer '{}' must declare at least one trigger glob",
                reviewer.name
            );
            assert!(
                !reviewer.prompt.trim().is_empty(),
                "reviewer '{}' must carry a prompt",
                reviewer.name
            );
        }
    }

    #[test]
    fn unprovisioned_capabilities_gate_guards_the_registry() {
        // The unprovisioned-capabilities reviewer is the authoring-time guard
        // against a reviewer declaring a capability this build cannot provision.
        // Pin its routing so a typo in its trigger or a flip from gate to advisor
        // fails here rather than silently disarming the guard.
        let path = Path::new(env!("CARGO_MANIFEST_DIR"))
            .join(CONFIG_DIR)
            .join(REGISTRY_FILE);
        let config = Config::load(&path).expect("shipped registry loads");
        let gate = config
            .reviewers
            .iter()
            .find(|r| r.name == "unprovisioned-capabilities")
            .expect("the unprovisioned-capabilities reviewer is present");
        assert_eq!(
            gate.mode,
            crate::reviewer::Mode::Gate,
            "unprovisioned-capabilities must be a gate, not an advisor"
        );
        assert!(
            gate.trigger.iter().any(|t| t == "bastion/reviewers.yaml"),
            "unprovisioned-capabilities must trigger on the registry it guards (got {:?})",
            gate.trigger
        );
        // Pin the policy clauses the container-runner work changed, so a prompt edit
        // that silently re-broadened the guard (back to blocking a `runner`, or
        // forward to letting `mcp`/`skills` through) fails here. The runner block is
        // now provisioned, a native `network: true` still fails closed, and `mcp` and
        // `skills` remain unprovisioned.
        let prompt = &gate.prompt;
        assert!(
            prompt.contains("the container `runner` block"),
            "the gate prompt must state the `runner` block is provisioned"
        );
        assert!(
            prompt.contains("does NOT yet provision the `mcp` or `skills`"),
            "the gate prompt must still treat `mcp` and `skills` as unprovisioned"
        );
        assert!(
            prompt.contains("NO `runner` block"),
            "the gate prompt must still block native `network: true` (no `runner`)"
        );
    }
}
